function exportContractorReportCsv(){var rows=getVisibleContractorRecords();var table=[["Contractor","Phone","Email","Region","Documents","Risk","GL Expiry","WC Expiry","Next Action","Address"]].concat(rows.map(function(row){return [row.name,row.phone,row.email,row.region,row.documents,row.risk,row.glExpiry,row.wcExpiry,row.nextAction,row.address]}));var csv='\uFEFF'+table.map(function(row){return row.map(function(cell){return '"'+String(cell==null?'':cell).replace(/"/g,'""')+'"'}).join(',')}).join('\n');downloadReportBlob(csv,'text/csv;charset=utf-8','citadel-contractors-report.csv')}
function normalizeReviewRecord(record){return {id:record.review_id||'',platform:record.platform||'',name:record.customer||record.name||'',title:record.review_title||record.review_name||'',text:record.review_text||'',rating:record.rating||record.score||'',status:record.status||record.result||'Monitor',date:record.review_date||record.last_updated||'',url:record.review_url||'',notesCount:Number(record.notes_count||0),alertsCount:Number(record.alerts_count||0),followupsCount:Number(record.followups_count||0)}}
