function bindReviewsPage(){if(reviewsPageEventsBound)return;reviewsPageEventsBound=true;pagePanel.addEventListener('click',function(event){if(activePage!=='reviews')return;var metric=event.target.closest('[data-review-metric]');if(metric){activeReviewMetric=metric.getAttribute('data-review-metric')||'all';reviewsData.selectedIndex=0;renderReviewsPage();return}if(event.target.closest('[data-review-report]')){exportReviewReportCsv();return}var row=event.target.closest('[data-review-index]');if(row){reviewsData.selectedIndex=Number(row.getAttribute('data-review-index'));renderReviewsPage()}});pagePanel.addEventListener('change',function(event){if(activePage!=='reviews')return;var field=event.target.closest('select[data-review-filter]');if(!field)return;reviewFilters[field.getAttribute('data-review-filter')]=field.value;reviewsData.selectedIndex=0;renderReviewsPage()});pagePanel.addEventListener('input',function(event){if(activePage!=='reviews')return;var search=event.target.closest('input[data-review-filter="search"]');if(!search)return;reviewFilters.search=search.value;window.clearTimeout(reviewSearchTimer);reviewSearchTimer=window.setTimeout(function(){reviewsData.selectedIndex=0;renderReviewsPage();var next=pagePanel.querySelector('input[data-review-filter="search"]');if(next){next.focus();next.setSelectionRange(next.value.length,next.value.length)}},180)});pagePanel.addEventListener('submit',function(event){if(activePage!=='reviews')return;var form=event.target.closest('[data-review-workspace]');if(!form)return;event.preventDefault();var selected=reviewsData.records[reviewsData.selectedIndex]||{};var data=new FormData(form);var type=form.getAttribute('data-review-workspace');var payload={review_id:selected.id};data.forEach(function(value,key){payload[key]=value});if(type==='note')saveReviewWorkspace('saveReviewNote',payload);if(type==='alert')saveReviewWorkspace('saveReviewAlert',payload);if(type==='followup')saveReviewWorkspace('saveReviewFollowUp',payload)})}
function saveReviewWorkspace(action,payload){reviewWorkspaceStatus='Saving...';if(activePage==='reviews')renderReviewsPage();var params=Object.keys(payload).map(function(key){return encodeURIComponent(key)+'='+encodeURIComponent(payload[key]||'')}).join('&');return jsonp(CITADEL_API_URL+'?action='+encodeURIComponent(action)+'&'+params).then(function(response){if(!response||!response.ok)throw new Error(response&&response.error?response.error:'Save failed');reviewWorkspaceStatus='Saved';return loadReviewsData()}).catch(function(){reviewWorkspaceStatus='Save failed';if(activePage==='reviews')renderReviewsPage()})}
function exportReviewReportCsv(){var rows=getVisibleReviewRecords();var table=[['Name','Platform','Rating','Status','Date','Title','Review Text','URL']].concat(rows.map(function(row){return [row.name,row.platform,row.rating,row.status,row.date,row.title,row.text,row.url]}));var csv='\uFEFF'+table.map(function(row){return row.map(function(cell){return '"'+String(cell==null?'':cell).replace(/"/g,'""')+'"'}).join(',')}).join('\n');downloadReportBlob(csv,'text/csv;charset=utf-8','citadel-reviews-report.csv')}
function loadReviewsData(){if(!CITADEL_API_URL){reviewsLoading=false;return}reviewsLoading=true;reviewsLoadError='';if(activePage==='reviews'&&!reviewsData.records.length)renderReviewsPage();jsonp(CITADEL_API_URL+'?action=getReviews').then(function(response){if(!response||!response.ok||!response.data)throw new Error(response&&response.error?response.error:'No reviews data returned');applyReviewsPayload(response.data);reviewsLoading=false;if(activePage==='reviews'||activePage==='command-center')renderContent()}).catch(function(error){reviewsLoading=false;reviewsLoadError='Reviews sheet not connected yet';console.warn('Reviews sheet load failed',error);if(activePage==='reviews')renderReviewsPage()})}
function renderStandardFilterCard(pageId){var filters=STANDARD_FILTERS[pageId]||STANDARD_FILTERS.tasks;return '<section class="standard-filter-card"><div><h3>Filters + Sort + Search</h3><p>Refine and find records the same way on every page</p></div><button type="button" data-standard-report>Reports</button><div class="standard-filters">'+filters.map(function(item){return '<label>'+escapeHtml(item[0])+'<select>'+renderSelectOptions(item[1],item[2],item[1])+'</select></label>'}).join('')+'<label>Search<input type="search" placeholder="Search this view"></label></div></section>'}

function bindStandardPage(){if(standardPageEventsBound)return;standardPageEventsBound=true;pagePanel.addEventListener("click",function(event){if(activePage==="command-center"||activePage==="liens"||activePage==="contractors")return;var metric=event.target.closest("[data-standard-metric]");if(metric){activeStandardMetric=metric.getAttribute("data-standard-metric")||"";renderStandardContent();return}if(event.target.closest("[data-standard-report]")){alert(getPageLabel(activePage)+" reports will be connected when this page source data is added.")}})}
function renderStandardContent(){var details=pageDetails[activePage]||pageDetails.tasks;var label=getPageLabel(activePage);pagePanel.className="page-panel standard-page";pagePanel.innerHTML='<div class="module-status-line"><span></span>Stable</div><div id="subTabs" class="sub-tabs" hidden></div><div class="metric-grid">'+details.metrics.map(function(item){return '<button type="button" class="metric-card standard-metric-button '+(activeStandardMetric===item[0]?'active':'')+'" data-standard-metric="'+escapeHtml(item[0])+'"><div class="metric-label">'+escapeHtml(item[0])+'</div><div class="metric-value">'+escapeHtml(item[1])+'</div><div class="metric-note">'+escapeHtml(item[2])+'</div></button>'}).join('')+'</div>'+renderStandardFilterCard(activePage)+'<div class="content-grid"><article class="work-card"><div class="card-heading"><h3>'+escapeHtml(label)+' Focus</h3><span>'+(activePage.indexOf("fleet")===0?"Fleet":"Today")+'</span></div><p id="focusCopy">'+escapeHtml(details.focus)+'</p></article><article class="work-card compact"><div class="card-heading"><h3>Queue Snapshot</h3><span>Priority</span></div><ul class="queue-list">'+details.queue.map(function(item){return '<li><span>'+escapeHtml(item[0])+'</span><strong>'+escapeHtml(item[1])+'</strong></li>'}).join('')+'</ul></article></div>';subTabs=document.querySelector("#subTabs");renderSubTabs()}

function loadLiensData(){if(!CITADEL_API_URL){liensLoading=false;return}if(!liensData.records.length)hydrateLiensFromCache();liensLoading=true;liensLoadError="";if(activePage==="liens"&&!liensData.records.length)renderContent();jsonp(CITADEL_API_URL+"?action=getLiens").then(function(response){if(!response||!response.ok||!response.data)throw new Error(response&&response.error?response.error:"No liens data returned");applyLiensPayload(response.data);saveLiensCache(response.data);liensLoading=false;if(activePage==="liens"||activePage==="command-center")renderContent()}).catch(function(error){liensLoading=false;liensLoadError="Unable to refresh lien records";console.warn("Liens sheet load failed",error);if(activePage==="liens")renderContent()})}
function jsonp(url){return new Promise(function(resolve,reject){var callback="citadelCallback"+Date.now()+Math.floor(Math.random()*10000);var script=document.createElement("script");var timeout=window.setTimeout(function(){cleanup();reject(new Error("Sheet request timed out"))},45000);function cleanup(){window.clearTimeout(timeout);delete window[callback];if(script.parentNode)script.parentNode.removeChild(script)}window[callback]=function(payload){cleanup();resolve(payload)};script.onerror=function(){cleanup();reject(new Error("Sheet request failed"))};script.src=url+"&callback="+callback;document.head.appendChild(script)})}
function loadContractorsData(){if(!CITADEL_API_URL){contractorsLoading=false;return}if(!contractorsData.records.length)hydrateContractorsFromCache();contractorsLoading=true;contractorsLoadError="";if(activePage==="contractors"&&!contractorsData.records.length)renderContent();jsonp(CITADEL_API_URL+"?action=getContractors").then(function(response){if(!response||!response.ok||!response.data)throw new Error(response&&response.error?response.error:"No contractor data returned");applyContractorsPayload(response.data);saveContractorsCache(response.data);contractorsLoading=false;if(activePage==="contractors"||activePage==="command-center")renderContent()}).catch(function(error){contractorsLoading=false;contractorsLoadError="Contractors sheet not connected yet";console.warn("Contractors sheet load failed",error);if(activePage==="contractors")renderContent()})}

function renderContent(){var label=getPageLabel(activePage);pageTitle.textContent=label;if(activePage==="command-center"){renderCommandCenter();bindCommandCenter();return}if(activePage==="liens"){renderLiensPage();bindLiensPage();return}if(activePage==="contractors"){renderContractorsPage();bindContractorsPage();return}if(activePage==="reviews"){renderReviewsPage();bindReviewsPage();if(!reviewsData.records.length&&!reviewsLoading&&!reviewsLoadError)loadReviewsData();return}if(activePage==="pricing"){renderPricingPage();bindPricingPage();if(!pricingState.rows.length&&!pricingState.loading&&!pricingState.error)loadPricingData();return}renderStandardContent();bindStandardPage()}
function setActivePage(pageId){activePage=pageId;renderNavigation();renderContent()}

initSettingsMenu();hydrateLiensFromCache();hydrateContractorsFromCache();setActivePage(activePage);loadLiensData();loadContractorsData();loadReviewsData();
